  3490→ *
  3491→ * The structure RedisModuleBlockedClient will be always deallocated when
  3492→ * running the list of clients blocked by a module that need to be unblocked. */
  3493→void unblockClientFromModule(client *c) {
  3494→    RedisModuleBlockedClient *bc = c->bpop.module_blocked_handle;
  3495→
  3496→    /* Call the disconnection callback if any. */
  3497→    if (bc->disconnect_callback) {
  3498→        RedisModuleCtx ctx = REDISMODULE_CTX_INIT;
  3499→        ctx.blocked_privdata = bc->privdata;
  3500→        ctx.module = bc->module;
  3501→        ctx.client = bc->client;
  3502→        bc->disconnect_callback(&ctx,bc);
  3503→        moduleFreeContext(&ctx);
  3504→    }
  3505→
  3506→    bc->client = NULL;
  3507→    /* Reset the client for a new query since, for blocking commands implemented
  3508→     * into modules, we do not it immediately after the command returns (and
  3509→     * the client blocks) in order to be still able to access the argument
  3510→     * vector from callbacks. */
  3511→    resetClient(c);
  3512→}
  3513→
  3514→/* Block a client in the context of a blocking command, returning an handle
  3515→ * which will be used, later, in order to unblock the client with a call to
  3516→ * RedisModule_UnblockClient(). The arguments specify callback functions
  3517→ * and a timeout after which the client is unblocked.
  3518→ *
  3519→ * The callbacks are called in the following contexts:
  3520→ *
  3521→ *     reply_callback:  called after a successful RedisModule_UnblockClient()
  3522→ *                      call in order to reply to the client and unblock it.
  3523→ *
  3524→ *     reply_timeout:   called when the timeout is reached in order to send an
  3525→ *                      error to the client.
  3526→ *
  3527→ *     free_privdata:   called in order to free the private data that is passed
  3528→ *                      by RedisModule_UnblockClient() call.
  3529→ */
  3530→RedisModuleBlockedClient *RM_BlockClient(RedisModuleCtx *ctx, RedisModuleCmdFunc reply_callback, RedisModuleCmdFunc timeout_callback, void (*free_privdata)(RedisModuleCtx*,void*), long long timeout_ms) {
  3531→    client *c = ctx->client;
  3532→    int islua = c->flags & CLIENT_LUA;
  3533→    int ismulti = c->flags & CLIENT_MULTI;
  3534→
  3535→    c->bpop.module_blocked_handle = zmalloc(sizeof(RedisModuleBlockedClient));
  3536→    RedisModuleBlockedClient *bc = c->bpop.module_blocked_handle;
  3537→
  3538→    /* We need to handle the invalid operation of calling modules blocking
  3539→     * commands from Lua or MULTI. We actually create an already aborted
  3540→     * (client set to NULL) blocked client handle, and actually reply with
  3541→     * an error. */
  3542→    bc->client = (islua || ismulti) ? NULL : c;
  3543→    bc->module = ctx->module;
  3544→    bc->reply_callback = reply_callback;
  3545→    bc->timeout_callback = timeout_callback;
  3546→    bc->disconnect_callback = NULL; /* Set by RM_SetDisconnectCallback() */
  3547→    bc->free_privdata = free_privdata;
  3548→    bc->privdata = NULL;
  3549→    bc->reply_client = createClient(-1);
  3550→    bc->reply_client->flags |= CLIENT_MODULE;
  3551→    bc->dbid = c->db->id;
  3552→    c->bpop.timeout = timeout_ms ? (mstime()+timeout_ms) : 0;
  3553→
  3554→    if (islua || ismulti) {
  3555→        c->bpop.module_blocked_handle = NULL;
  3556→        addReplyError(c, islua ?
  3557→            "Blocking module command called from Lua script" :
  3558→            "Blocking module command called from transaction");
  3559→    } else {
  3560→        blockClient(c,BLOCKED_MODULE);
  3561→    }
  3562→    return bc;
  3563→}
  3564→
  3565→/* Unblock a client blocked by `RedisModule_BlockedClient`. This will trigger
  3566→ * the reply callbacks to be called in order to reply to the client.
  3567→ * The 'privdata' argument will be accessible by the reply callback, so
  3568→ * the caller of this function can pass any value that is needed in order to
  3569→ * actually reply to the client.
  3570→ *
  3571→ * A common usage for 'privdata' is a thread that computes something that
  3572→ * needs to be passed to the client, included but not limited some slow
  3573→ * to compute reply or some reply obtained via networking.
  3574→ *
  3575→ * Note: this function can be called from threads spawned by the module. */
  3576→int RM_UnblockClient(RedisModuleBlockedClient *bc, void *privdata) {
  3577→    pthread_mutex_lock(&moduleUnblockedClientsMutex);
  3578→    bc->privdata = privdata;
  3579→    listAddNodeTail(moduleUnblockedClients,bc);
  3580→    if (write(server.module_blocked_pipe[1],"A",1) != 1) {
  3581→        /* Ignore the error, this is best-effort. */
  3582→    }
  3583→    pthread_mutex_unlock(&moduleUnblockedClientsMutex);
  3584→    return REDISMODULE_OK;
  3585→}
  3586→
  3587→/* Abort a blocked client blocking operation: the client will be unblocked
  3588→ * without firing any callback. */
  3589→int RM_AbortBlock(RedisModuleBlockedClient *bc) {
  3590→    bc->reply_callback = NULL;
  3591→    bc->disconnect_callback = NULL;
  3592→    return RM_UnblockClient(bc,NULL);
  3593→}
  3594→
  3595→/* Set a callback that will be called if a blocked client disconnects
  3596→ * before the module has a chance to call RedisModule_UnblockClient()
  3597→ *
  3598→ * Usually what you want to do there, is to cleanup your module state
  3599→ * so that you can call RedisModule_UnblockClient() safely, otherwise
  3600→ * the client will remain blocked forever if the timeout is large.
  3601→ *
  3602→ * Notes:
  3603→ *
  3604→ * 1. It is not safe to call Reply* family functions here, it is also
  3605→ *    useless since the client is gone.
  3606→ *
  3607→ * 2. This callback is not called if the client disconnects because of
  3608→ *    a timeout. In such a case, the client is unblocked automatically
  3609→ *    and the timeout callback is called.
  3610→ */
  3611→void RM_SetDisconnectCallback(RedisModuleBlockedClient *bc, RedisModuleDisconnectFunc callback) {
  3612→    bc->disconnect_callback = callback;
